solution_code:
#include <iostream>

int main()
{
    int millivolts {};
    std::cin >> millivolts;

    bool inRange   { millivolts >= 3000 && millivolts <= 3600 };
    bool isNominal { millivolts == 3300 };

    std::cout << std::boolalpha;
    std::cout << "In range: " << inRange   << '\n';
    std::cout << "Nominal: "  << isNominal << '\n';
    return 0;
}

