    bool bothNonNeg     { a >= 0 && b >= 0 };  // fixed: || -> &&

    std::cout << std::boolalpha;
    std::cout << "Sum positive: "     << sumPositive << '\n';
    std::cout << "Both non-negative: " << bothNonNeg  << '\n';
    return 0;
}
